const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

async function runBackup() {
  console.log('🚀 开始备份到飞书表格...');

  // 1. 获取表格现有记录
  const docToken = 'GaDhdogBhoQWRQx5lG4cpyQknUb';
  const tableBlockId = 'doxcnwhyXhKB6ORGWeAHoW6vlJf';

  const blocksRes = await feishu_doc({ action: 'list_blocks', doc_token: docToken });
  const blocks = blocksRes.blocks;
  const tableBlock = blocks.find(b => b.block_id === tableBlockId && b.block_type === 31);
  if (!tableBlock) throw new Error('未找到表格');

  const columnSize = tableBlock.table.property.column_size;
  const cellBlockIds = tableBlock.children;
  const blockMap = new Map(blocks.map(b => [b.block_id, b]));

  const existingPaths = new Set();
  for (let i = columnSize; i < cellBlockIds.length; i += columnSize) {
    const cellBlockId = cellBlockIds[i + 2];
    if (cellBlockId) {
      const cellBlock = blockMap.get(cellBlockId);
      if (cellBlock?.block_type === 32 && cellBlock.children?.[0]) {
        const textBlock = blockMap.get(cellBlock.children[0]);
        if (textBlock?.block_type === 2) {
          const text = textBlock.text.elements.map(e => e.text_run?.content || '').join('');
          if (text) existingPaths.add(text);
        }
      }
    }
  }
  console.log('表格已有备份记录数:', Math.floor((cellBlockIds.length - columnSize) / columnSize));

  // 2. 扫描文件
  function getWorkspaceFiles() {
    const files = [];
    const includeGlobs = [
      'memory/**/*.md', 'AGENTS.md', 'USER.md', 'SOUL.md', 'MEMORY.md',
      'IDENTITY.md', 'TOOLS.md', 'HEARTBEAT.md', 'scripts/**/*.js',
      'skills/**/*.md'
    ];
    const excludePatterns = [/node_modules/, /\\.git/, /backup/, /temp/, /\\.log$/, /\\.bak$/];

    function matchesGlob(filePath, globs) {
      return globs.some(glob => {
        const pattern = glob.replace(/\\*\\*/g, '.*').replace(/\\*/g, '[^/]*').replace(/\\?/g, '.');
        return new RegExp('^' + pattern + '$').test(filePath.replace(/\\\\/g, '/'));
      });
    }

    function scan(dir) {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);
        const relPath = path.relative(process.cwd(), fullPath);
        if (excludePatterns.some(p => p.test(relPath))) { if (entry.isDirectory()) scan(fullPath); continue; }
        if (!matchesGlob(relPath, includeGlobs)) { if (entry.isDirectory()) scan(fullPath); continue; }
        if (entry.isFile()) files.push({ path: fullPath, relPath, size: fs.statSync(fullPath).size });
        else if (entry.isDirectory()) scan(fullPath);
      }
    }
    scan(process.cwd());
    return files;
  }

  const files = getWorkspaceFiles();
  console.log('扫描到文件数:', files.length);

  // 3. 筛选需备份的文件（去重）
  const toBackup = files.filter(f => !existingPaths.has(f.relPath));
  console.log('需要备份的文件数:', toBackup.length);

  if (toBackup.length === 0) {
    console.log('没有需要备份的文件，退出');
    return;
  }

  // 4. 准备行数据
  const now = new Date().toISOString();
  const rows = toBackup.map(file => {
    const hash = crypto.createHash('sha256').update(fs.readFileSync(file.path)).digest('hex').substring(0, 16) + '...';
    const getFileType = (p) => {
      const name = path.basename(p).toLowerCase();
      if (name.endsWith('.md')) return p.startsWith('memory/') ? '记忆文件' : '文档';
      if (/\\.js$/.test(p) || /\\.ts$/.test(p)) return '脚本文件';
      if (/\\.json$/.test(p)) return '配置文件';
      if (p.includes('skill')) return '技能文件';
      return '其他';
    };
    return [
      path.basename(file.path),
      getFileType(file.relPath),
      file.relPath,
      now,
      file.size,
      'sha256:' + hash,
      '成功',
      '自动备份（第379次训练）'
    ];
  });

  // 5. 写入表格（追加）
  console.log('正在写入', rows.length, '行数据...');
  const result = await feishu_doc({
    action: 'write_table_cells',
    doc_token: docToken,
    table_block_id: tableBlockId,
    values: rows
  });

  if (result.cells_written) {
    console.log('✅ 备份成功！写入单元格数:', result.cells_written);
    toBackup.forEach(f => console.log('  -', f.relPath));
  } else {
    console.error('❌ 备份失败:', result);
  }
}

runBackup().catch(e => console.error('异常:', e));
