#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

const includeGlobs = [
  'memory/**/*.md',
  'AGENTS.md',
  'USER.md',
  'SOUL.md',
  'MEMORY.md',
  'IDENTITY.md',
  'TOOLS.md',
  'HEARTBEAT.md',
  'scripts/**/*.js',
  'scripts/**/*.json',
  'skills/**/*.md'
];
const excludePatterns = [/node_modules/, /\.git/, /backup/, /temp/, /\.log$/, /\.bak$/];

function matchesGlob(filePath, globs) {
  const normalized = filePath.replace(/\\/g, '/');
  return globs.some(glob => {
    let pattern = glob
      .replace(/\*\*/g, '.__PATH__SEPARATOR__.')
      .replace(/\*/g, '[^/]*')
      .replace(/\?/g, '.')
      .replace(/\./g, '\\.')
      .replace(/__PATH__SEPARATOR__/g, '.*');
    return new RegExp('^' + pattern + '$').test(normalized);
  });
}

const files = [];
function scan(dir) {
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name);
    const relPath = path.relative(process.cwd(), fullPath);

    if (excludePatterns.some(p => p.test(relPath))) {
      if (entry.isDirectory()) scan(fullPath);
      continue;
    }

    if (!matchesGlob(relPath, includeGlobs)) {
      if (entry.isDirectory()) scan(fullPath);
      continue;
    }

    if (entry.isFile()) {
      files.push({
        path: fullPath,
        relPath,
        size: fs.statSync(fullPath).size,
        mtime: fs.statSync(fullPath).mtime
      });
    } else if (entry.isDirectory()) {
      scan(fullPath);
    }
  }
}
scan(process.cwd());

files.sort((a, b) => a.relPath.localeCompare(b.relPath));

console.log(JSON.stringify({ total: files.length, files: files.map(f => ({ relPath: f.relPath, size: f.size })) }, null, 2));

